// Format transcript with speaker labels and timestamps
const segments = $('4. WayinVideo — Get Transcript Results').item.json.data.transcript || [];

if (segments.length === 0) {
  throw new Error('Transcript is empty — check if the recording URL is valid and publicly accessible.');
}

// Format with speaker labels and timestamps
const formattedTranscript = segments
  .map(s => {
    const ms = Math.floor(s.start / 1000);
    const mm = Math.floor(ms / 60);
    const ss = ms % 60;
    return `[${s.speaker} | ${mm}:${ss.toString().padStart(2, '0')}] ${s.text.trim()}`;
  })
  .join('\n');

// Duration
const lastSegment = segments[segments.length - 1];
const totalMs = lastSegment?.end || 0;
const totalMinutes = Math.floor(totalMs / 60000);
const totalSeconds = Math.floor((totalMs % 60000) / 1000);
const durationFormatted = `${totalMinutes}:${totalSeconds.toString().padStart(2, '0')}`;

// Speakers
const speakers = [...new Set(segments.map(s => s.speaker))];

// Word count
const wordCount = segments.map(s => s.text).join(' ').split(/\s+/).length;

// Form data
const episodeNumber = $('1. Form — Episode Recording + Details').item.json['Episode Number'];
const podcastName = $('1. Form — Episode Recording + Details').item.json['Podcast Name'];
const hostName = $('1. Form — Episode Recording + Details').item.json['Host Name'];
const guestName = $('1. Form — Episode Recording + Details').item.json['Guest Name'] || '';
const guestTitle = $('1. Form — Episode Recording + Details').item.json['Guest Title / Company'] || '';
const episodeTopic = $('1. Form — Episode Recording + Details').item.json['Episode Main Topic'];
const podcastNiche = $('1. Form — Episode Recording + Details').item.json['Podcast Niche'];
const ctaLink = $('1. Form — Episode Recording + Details').item.json['CTA / Subscribe Link'];
const recordingUrl = $('1. Form — Episode Recording + Details').item.json['Episode Recording URL'];

const isInterviewEpisode = guestName.trim().length > 0;

return [{
  json: {
    formattedTranscript,
    durationFormatted,
    totalMinutes,
    wordCount,
    speakerCount: speakers.length,
    speakers: speakers.join(', '),
    episodeNumber,
    podcastName,
    hostName,
    guestName,
    guestTitle,
    episodeTopic,
    podcastNiche,
    ctaLink,
    recordingUrl,
    isInterviewEpisode
  }
}];

// Parse AI show notes output
const output = $input.first().json.output || '';

// Extract all sections
const episodeTitleMatch = output.match(/EPISODE_TITLE:\s*([\s\S]*?)(?=\nSEO_DESCRIPTION:|$)/);
const seoDescMatch = output.match(/SEO_DESCRIPTION:\s*([\s\S]*?)(?=\nKEY_TAKEAWAYS:|$)/);
const takeawaysMatch = output.match(/KEY_TAKEAWAYS:\s*([\s\S]*?)(?=\nRESOURCES_MENTIONED:|$)/);
const resourcesMatch = output.match(/RESOURCES_MENTIONED:\s*([\s\S]*?)(?=\nTIMESTAMPED_HIGHLIGHTS:|$)/);
const timestampsMatch = output.match(/TIMESTAMPED_HIGHLIGHTS:\s*([\s\S]*?)(?=\nGUEST_BIO:|$)/);
const guestBioMatch = output.match(/GUEST_BIO:\s*([\s\S]*?)(?=\nCTA_BLOCK:|$)/);
const ctaMatch = output.match(/CTA_BLOCK:\s*([\s\S]*?)(?=\nFULL_SHOW_NOTES:|$)/);
const fullNotesMatch = output.match(/FULL_SHOW_NOTES:\s*([\s\S]*)$/);

const episodeTitle = episodeTitleMatch ? episodeTitleMatch[1].trim() : '';
const seoDescription = seoDescMatch ? seoDescMatch[1].trim() : '';
const keyTakeaways = takeawaysMatch ? takeawaysMatch[1].trim() : '';
const resourcesMentioned = resourcesMatch ? resourcesMatch[1].trim() : 'No resources mentioned in this episode';
const timestampedHighlights = timestampsMatch ? timestampsMatch[1].trim() : '';
const guestBio = guestBioMatch ? guestBioMatch[1].trim() : 'Solo episode — no guest';
const ctaBlock = ctaMatch ? ctaMatch[1].trim() : '';
const fullShowNotes = fullNotesMatch ? fullNotesMatch[1].trim() : '';

if (!episodeTitle || !seoDescription || !fullShowNotes) {
  throw new Error('Could not parse show notes from AI output. Check the AI prompt format.');
}

const wordCount = fullShowNotes.split(/\s+/).filter(w => w.length > 0).length;

// Get episode data
const epData = $('7. Code — Format Transcript').item.json;

return [{
  json: {
    episodeTitle,
    seoDescription,
    keyTakeaways,
    resourcesMentioned,
    timestampedHighlights,
    guestBio,
    ctaBlock,
    fullShowNotes,
    wordCount,
    episodeNumber: epData.episodeNumber,
    podcastName: epData.podcastName,
    hostName: epData.hostName,
    guestName: epData.guestName,
    episodeTopic: epData.episodeTopic,
    durationFormatted: epData.durationFormatted,
    recordingUrl: epData.recordingUrl,
    ctaLink: epData.ctaLink
  }
}];
